	checks := []string{
		"# ",                    // title
		"## Summary",            // summary section
		"## Grade Distribution", // grade dist
		"## Dimension Averages", // dimensions
		"## By Language",        // languages
		"## All Units",          // all units
		"| Unit |",              // table header
		"Score",                 // unit name in table
		"CertifyUnit",           // unit name in table
		"parse",                 // ts unit
		"complexity too high",   // observation detail
